const DEFAULT_MODEL = "ollama/qwen3:14b";
const REQUIRED_HANDOFF_ORDER: HermesDeploymentRole[] = [
  "hermes_planner",
  "worker_coder",
  "verifier",
  "memory_summarizer",
];
const REQUIRED_GATE_REPORTS: Array<{
  after: HermesDeploymentRole;
  require: string[];
}> = [
  {
    after: "hermes_planner",
    require: ["task_package", "risk_class", "validation_commands", "rollback_path"],
  },
  {
    after: "worker_coder",
    require: ["changed_files", "validation_result", "rollback_path"],
  },
  {
    after: "verifier",
    require: ["promotion_report", "promote_or_rollback_decision"],
  },
  {
    after: "memory_summarizer",
    require: ["learning_state", "next_safe_task_context"],
  },
];

export function buildHermesDeploymentPlan(
  params: {
    request?: string;
    currentModel?: string;
    now?: Date;
  } = {},
): HermesDeploymentPlan {
  const currentModel = params.currentModel?.trim() || DEFAULT_MODEL;
  const request =
    params.request?.trim() ||
    "Deploy Hermes as a controlled OpenClaw planner that hands tasks to worker, verifier, and memory roles.";
  const roles: HermesDeploymentPlan["roles"] = [
    {
      id: "hermes_planner",
      owns: ["task packaging", "risk classification", "next task selection"],
      first_model: currentModel,
      future_model_class: "strong reasoning model",
      entrypoint: "openclaw hermes plan / openclaw hermes decide",
      report: "task_package",
    },
    {
      id: "worker_coder",
      owns: ["bounded patches", "targeted validation", "changed-file report"],
      first_model: currentModel,
      future_model_class: "coding-specialized local model",
      entrypoint: "OpenClaw worker task flow step",
      report: "worker_report",
    },
    {
      id: "verifier",
      owns: ["validation review", "rollback decision", "promotion decision"],
      first_model: currentModel,
      future_model_class: "conservative verification model",
      entrypoint: "openclaw hermes promote",
      report: "promotion_report",
    },
    {
      id: "memory_summarizer",
      owns: ["success patterns", "failure patterns", "compact next-task context"],
      first_model: currentModel,
      future_model_class: "small summary model",
      entrypoint: "openclaw hermes learn",
      report: "learning_state",
    },
  ];

  return {
    schema: "openclaw.hermes.deployment_plan.v1",
    created_at: (params.now ?? new Date()).toISOString(),
    dry_run: true,
    mode: "sequential_handoff",
    request,
    current_model: currentModel,
    roles,
    handoff_order: roles.map((role) => role.id),
    resource_policy: [
      "Run one local model role at a time.",
      "Do not parallelize large local model turns.",
      "Prefer deterministic validation before model judgment.",
      "Stop the loop when model availability or validation state is unknown.",
    ],
    promotion_policy: [
      "Promote only after targeted validation passes.",
      "Record failed validation as a failure pattern.",
      "Require rollback when validation fails.",
      "Create the next task only after verifier and memory reports exist.",
    ],
    forbidden_actions: [
      "Do not create a second OpenClaw project.",
      "Do not enable real trading, payment, credential writes, deployment, or external writes.",
      "Do not let Hermes patch files during a worker turn.",
      "Do not silently switch models when the requested role model is unavailable.",
    ],
    next_safe_task:
      "Wire the sequential handoff plan into Task Flow as a dry-run skeleton before assigning separate models.",
  };
}

export function buildHermesTaskFlowSkeleton(
  params: {
    request?: string;
    currentModel?: string;
    now?: Date;
  } = {},
): HermesTaskFlowSkeleton {
  const now = params.now ?? new Date();
  const deploymentPlan = buildHermesDeploymentPlan({
    request: params.request,
    currentModel: params.currentModel,
    now,
  });
  const flowId = `hermes-flow-${now.toISOString().replace(/[-:.]/g, "").slice(0, 15)}`;
  const commandByRole: Record<HermesDeploymentRole, string> = {
    hermes_planner: "openclaw hermes plan <request>",
    worker_coder: "OpenClaw worker applies the bounded task package",
    verifier: "openclaw hermes promote --trace-id <trace_id> --validate <command>",
    memory_summarizer: "openclaw hermes learn --trace-id <trace_id> --status <success|failure>",
  };

  return {
    schema: "openclaw.hermes.taskflow_skeleton.v1",
    created_at: now.toISOString(),
    dry_run: true,
    flow_id: flowId,
    sync_mode: "managed",
    status: "planned",
    deployment_plan: deploymentPlan,
    steps: deploymentPlan.handoff_order.map((role, index) => {
      const rolePlan = deploymentPlan.roles.find((entry) => entry.id === role);
      return {
        id: role,
        order: index + 1,
        status: "pending",
        owner: role,
        command: commandByRole[role],
        expected_report: rolePlan?.report ?? "report",
        blocks_parallel_model_runs: true,
      };
    }),
    gates: [
      {
        after: "hermes_planner",
        require: ["task_package", "risk_class", "validation_commands", "rollback_path"],
      },
      {
        after: "worker_coder",
        require: ["changed_files", "validation_result", "rollback_path"],
      },
      {
        after: "verifier",
        require: ["promotion_report", "promote_or_rollback_decision"],
      },
      {
        after: "memory_summarizer",
        require: ["learning_state", "next_safe_task_context"],
      },
    ],
  };
}

export async function writeHermesTaskFlowSkeletonArtifact(params: {
  repoRoot: string;
  outputDir?: string;
  request?: string;
  currentModel?: string;
  now?: Date;
}): Promise<HermesTaskFlowSkeletonArtifact> {
  const skeleton = buildHermesTaskFlowSkeleton({
    request: params.request,
    currentModel: params.currentModel,
    now: params.now,
  });
  const outputDir = ensureInsideWorkspace(
    params.repoRoot,
    params.outputDir ?? "reports/hermes-agent/state",
  );
  await mkdir(outputDir, { recursive: true });
  const filePath = resolve(outputDir, `${skeleton.flow_id}-taskflow-skeleton.json`);
  await writeFile(filePath, `${JSON.stringify(skeleton, null, 2)}\n`, "utf8");
  return {
    path: filePath,
    skeleton,
  };
}

export async function validateHermesTaskFlowSkeletonArtifact(params: {
  repoRoot: string;
  artifactPath: string;
  now?: Date;
}): Promise<HermesTaskFlowSkeletonValidation> {
  const artifactPath = ensureInsideWorkspace(params.repoRoot, params.artifactPath);
  const failures: string[] = [];
  let parsed: unknown;

  try {
    parsed = JSON.parse(await readFile(artifactPath, "utf8"));
  } catch (error) {
    failures.push(
      `artifact JSON parse failed: ${error instanceof Error ? error.message : String(error)}`,
    );
  }

  if (parsed !== undefined) {
    failures.push(...validateHermesTaskFlowSkeleton(parsed));
  }

  const flowId = isRecord(parsed) && typeof parsed.flow_id === "string" ? parsed.flow_id : "";

  return {
    schema: "openclaw.hermes.taskflow_skeleton.validation.v1",
    created_at: (params.now ?? new Date()).toISOString(),
    path: artifactPath,
    status: failures.length === 0 ? "pass" : "fail",
    failures,
    ready_for_registry: failures.length === 0,
    flow_id: flowId,
  };
}

export async function writeHermesTaskFlowRegistryStagingArtifact(params: {
  repoRoot: string;
  artifactPath: string;
  outputDir?: string;
  now?: Date;
}): Promise<HermesTaskFlowRegistryStagingArtifact> {
  const artifactPath = ensureInsideWorkspace(params.repoRoot, params.artifactPath);
  const validation = await validateHermesTaskFlowSkeletonArtifact({
    repoRoot: params.repoRoot,
    artifactPath,
    now: params.now,
  });
  if (validation.status !== "pass") {
    throw new Error("Hermes Task Flow skeleton must pass validation before registry staging.");
  }

  const skeleton = JSON.parse(await readFile(artifactPath, "utf8")) as HermesTaskFlowSkeleton;
  const outputDir = ensureInsideWorkspace(
    params.repoRoot,
    params.outputDir ?? "reports/hermes-agent/state",
  );
  await mkdir(outputDir, { recursive: true });
  const record: HermesTaskFlowRegistryStagingRecord = {
    schema: "openclaw.hermes.taskflow_registry_staging.v1",
    created_at: (params.now ?? new Date()).toISOString(),
    dry_run: true,
    status: "staged",
    flow_id: skeleton.flow_id,
    source_artifact: artifactPath,
    validation,
    registry_mode: "staging_dry_run",
    taskflow_registry_write: false,
    worker_execution: false,
    model_invoked: false,
    sync_mode: "managed",
    steps: skeleton.steps,
    gates: skeleton.gates,
    promotion_blockers: [
      "Task Flow registry write is disabled for this staging artifact.",
      "Worker execution is disabled for this staging artifact.",
      "Model invocation is disabled for this staging artifact.",
    ],
    next_safe_task:
      "Add an explicit registry-write promotion gate before writing this flow into the Task Flow registry.",
  };
  const filePath = resolve(outputDir, `${record.flow_id}-taskflow-registry-staging.json`);
  await writeFile(filePath, `${JSON.stringify(record, null, 2)}\n`, "utf8");
  return {
    path: filePath,
    record,
  };
}

export async function writeHermesTaskFlowRegistryPromotionGateArtifact(params: {
  repoRoot: string;
  stagingPath: string;
  outputDir?: string;
  now?: Date;
}): Promise<HermesTaskFlowRegistryPromotionGateArtifact> {
  const stagingPath = ensureInsideWorkspace(params.repoRoot, params.stagingPath);
  const failures: string[] = [];
  let parsed: unknown;

  try {
    parsed = JSON.parse(await readFile(stagingPath, "utf8"));
  } catch (error) {
    failures.push(
      "staging JSON parse failed: " + (error instanceof Error ? error.message : String(error)),
    );
  }

  if (parsed !== undefined) {
    failures.push(...validateHermesTaskFlowRegistryStaging(parsed));
  }

  const record = parsed as Partial<HermesTaskFlowRegistryStagingRecord> | undefined;
  if (record?.source_artifact && typeof record.source_artifact === "string") {
    const sourceValidation = await validateHermesTaskFlowSkeletonArtifact({
      repoRoot: params.repoRoot,
      artifactPath: record.source_artifact,
      now: params.now,
    });
    if (sourceValidation.status !== "pass") {
      failures.push("source skeleton validation must pass before registry promotion");
    }
    if (sourceValidation.flow_id !== record.flow_id) {
      failures.push("source skeleton flow_id must match the staging flow_id");
    }
  }

  const outputDir = ensureInsideWorkspace(
    params.repoRoot,
    params.outputDir ?? "reports/hermes-agent/state",
  );
  await mkdir(outputDir, { recursive: true });
  const flowId =
    isRecord(parsed) && typeof parsed.flow_id === "string" && parsed.flow_id.trim() !== ""
      ? parsed.flow_id
      : "unknown-flow";
  const gate: HermesTaskFlowRegistryPromotionGate = {
    schema: "openclaw.hermes.taskflow_registry_promotion_gate.v1",
    created_at: (params.now ?? new Date()).toISOString(),
    dry_run: true,
    staging_artifact: stagingPath,
    flow_id: flowId,
    status: failures.length === 0 ? "manual_approval_required" : "blocked",
    registry_write_allowed: false,
    operator_approval_required: true,
    taskflow_registry_write: false,
    worker_execution: false,
    model_invoked: false,
    validation_status: failures.length === 0 ? "pass" : "fail",
    failures,
    blocked_actions: [
      "automatic Task Flow registry write",
      "worker execution from Hermes staging",
      "model invocation during registry promotion",
    ],
    next_safe_task:
      "Implement a separate no-op registry writer adapter with tests before any real Task Flow registry write path.",
  };
  const filePath = resolve(outputDir, flowId + "-taskflow-registry-promotion-gate.json");
  await writeFile(filePath, JSON.stringify(gate, null, 2) + "\n", "utf8");
  return {
    path: filePath,
    gate,
  };
}

