export async function writeHermesTaskFlowRegistrySnapshotArtifact(params: {
  repoRoot: string;
  taskFlowListJsonPath?: string;
  flowIdHint?: string;
  outputDir?: string;
  now?: Date;
}): Promise<HermesTaskFlowRegistrySnapshotArtifact> {
  const outputDir = ensureInsideWorkspace(
    params.repoRoot,
    params.outputDir ?? "reports/hermes-agent/state",
  );
  await mkdir(outputDir, { recursive: true });

  const failures: string[] = [];
  let inputArtifact: string | null = null;
  let source: HermesTaskFlowRegistrySnapshot["source"] = "empty_snapshot";
  let flows: HermesTaskFlowRegistrySnapshot["flows"] = [];

  if (params.taskFlowListJsonPath) {
    source = "openclaw_tasks_flow_list_json";
    inputArtifact = ensureInsideWorkspace(params.repoRoot, params.taskFlowListJsonPath);
    try {
      const parsedSnapshot = JSON.parse(await readFile(inputArtifact, "utf8"));
      if (!Array.isArray(parsedSnapshot) && !isRecord(parsedSnapshot)) {
        failures.push("Task Flow list JSON must be an object or array");
      }
      flows = normalizeSnapshotFlowRecords(parsedSnapshot);
    } catch (error) {
      failures.push(
        "Task Flow list JSON read failed: " +
          (error instanceof Error ? error.message : String(error)),
      );
    }
  }

  const flowIdHint = params.flowIdHint?.trim() || null;
  const status = failures.length === 0 ? "snapshot_ready" : "blocked";
  const artifactToken = sanitizeArtifactToken(flowIdHint ?? "taskflow-registry");
  const snapshot: HermesTaskFlowRegistrySnapshot = {
    schema: "openclaw.hermes.taskflow_registry_snapshot.v1",
    created_at: (params.now ?? new Date()).toISOString(),
    dry_run: true,
    read_only: true,
    source,
    input_artifact: inputArtifact,
    flow_id_hint: flowIdHint,
    status,
    sqlite_read: false,
    taskflow_registry_write: false,
    sqlite_write: false,
    worker_execution: false,
    model_invoked: false,
    validation_status: status === "snapshot_ready" ? "pass" : "fail",
    failures,
    count: flows.length,
    flows,
    next_safe_task:
      status === "snapshot_ready"
        ? "Feed this snapshot artifact into read-taskflow-registry-dry-run before any registry writer review."
        : "Fix the Task Flow list JSON artifact before registry read comparison.",
  };
  const filePath = resolve(outputDir, artifactToken + "-taskflow-registry-snapshot.json");
  await writeFile(filePath, JSON.stringify(snapshot, null, 2) + "\n", "utf8");
  return {
    path: filePath,
    snapshot,
  };
}
export async function writeHermesTaskFlowRegistryReadAdapterArtifact(params: {
  repoRoot: string;
  approvalValidationPath: string;
  registrySnapshotPath?: string;
  outputDir?: string;
  now?: Date;
}): Promise<HermesTaskFlowRegistryReadAdapterArtifact> {
  const approvalValidationPath = ensureInsideWorkspace(
    params.repoRoot,
    params.approvalValidationPath,
  );
  const failures: string[] = [];
  let parsedValidation: unknown;

  try {
    parsedValidation = JSON.parse(await readFile(approvalValidationPath, "utf8"));
  } catch (error) {
    failures.push(
      "approval validation JSON parse failed: " +
        (error instanceof Error ? error.message : String(error)),
    );
  }

  if (parsedValidation !== undefined) {
    failures.push(...validateHermesTaskFlowRegistryOperatorApprovalValidation(parsedValidation));
  }

  const approvalArtifact =
    isRecord(parsedValidation) && typeof parsedValidation.approval_artifact === "string"
      ? parsedValidation.approval_artifact
      : null;
  let parsedApproval: unknown;
  if (approvalArtifact) {
    try {
      const approvalPath = ensureInsideWorkspace(params.repoRoot, approvalArtifact);
      parsedApproval = JSON.parse(await readFile(approvalPath, "utf8"));
      failures.push(...validateHermesTaskFlowRegistryOperatorApprovalRequest(parsedApproval));
    } catch (error) {
      failures.push(
        "operator approval read failed: " +
          (error instanceof Error ? error.message : String(error)),
      );
    }
  }

  let snapshotFlow: Record<string, unknown> | null = null;
  let registrySnapshotArtifact: string | null = null;
  let snapshotRead = false;
  if (params.registrySnapshotPath) {
    try {
      registrySnapshotArtifact = ensureInsideWorkspace(
        params.repoRoot,
        params.registrySnapshotPath,
      );
      const parsedSnapshot = JSON.parse(await readFile(registrySnapshotArtifact, "utf8"));
      const flowId = readFlowId(parsedValidation);
      snapshotFlow = findSnapshotFlowRecord(parsedSnapshot, flowId);
      snapshotRead = true;
    } catch (error) {
      failures.push(
        "registry snapshot read failed: " +
          (error instanceof Error ? error.message : String(error)),
      );
    }
  }

  const outputDir = ensureInsideWorkspace(
    params.repoRoot,
    params.outputDir ?? "reports/hermes-agent/state",
  );
  await mkdir(outputDir, { recursive: true });
  const flowId = readFlowId(parsedValidation);
  const desiredRegistryState = readDesiredRegistryStateFromApproval(parsedApproval, flowId);
  const validationStatus = failures.length === 0 ? "pass" : "fail";
  const comparison = buildRegistryReadComparison({
    flowId,
    validationStatus,
    snapshotProvided: Boolean(params.registrySnapshotPath),
    snapshotFlow,
  });
  const report: HermesTaskFlowRegistryReadAdapterReport = {
    schema: "openclaw.hermes.taskflow_registry_read_adapter.v1",
    created_at: (params.now ?? new Date()).toISOString(),
    dry_run: true,
    read_only: true,
    adapter_mode: "artifact_snapshot_read",
    approval_validation_artifact: approvalValidationPath,
    approval_artifact: approvalArtifact,
    registry_snapshot_artifact: registrySnapshotArtifact,
    flow_id: flowId,
    status: validationStatus === "pass" ? "compared" : "blocked",
    registry_snapshot_read: snapshotRead,
    sqlite_read: false,
    taskflow_registry_write: false,
    sqlite_write: false,
    worker_execution: false,
    model_invoked: false,
    validation_status: validationStatus,
    failures,
    desired_registry_state: desiredRegistryState,
    current_registry_state:
      snapshotRead && snapshotFlow
        ? {
            source: "snapshot_artifact",
            flow_state: "present",
            flow_id: flowId,
            ...readOptionalSnapshotFlowFields(snapshotFlow),
          }
        : snapshotRead
          ? {
              source: "snapshot_artifact",
              flow_state: "missing",
              flow_id: flowId,
            }
          : {
              source: "not_loaded",
              flow_state: "unknown",
              flow_id: flowId,
              reason:
                "No registry snapshot was provided; this adapter did not read SQLite or mutate Task Flow state.",
            },
    comparison,
    next_safe_task:
      validationStatus === "pass"
        ? "Add an explicit registry writer review gate after this read-only snapshot comparison."
        : "Fix the approval validation artifact before reading registry snapshots.",
  };
  const filePath = resolve(outputDir, flowId + "-taskflow-registry-read-adapter.json");
  await writeFile(filePath, JSON.stringify(report, null, 2) + "\n", "utf8");
  return {
    path: filePath,
    report,
  };
}

export async function writeHermesTaskFlowRegistryWriterReviewArtifact(params: {
  repoRoot: string;
  readAdapterPath: string;
  outputDir?: string;
  now?: Date;
}): Promise<HermesTaskFlowRegistryWriterReviewArtifact> {
  const readAdapterPath = ensureInsideWorkspace(params.repoRoot, params.readAdapterPath);
  const failures: string[] = [];
  let parsedReadAdapter: unknown;

  try {
    parsedReadAdapter = JSON.parse(await readFile(readAdapterPath, "utf8"));
  } catch (error) {
    failures.push(
      "registry read adapter JSON parse failed: " +
        (error instanceof Error ? error.message : String(error)),
    );
  }

  if (parsedReadAdapter !== undefined) {
    failures.push(...validateHermesTaskFlowRegistryReadAdapterReport(parsedReadAdapter));
    if (isRecord(parsedReadAdapter) && parsedReadAdapter.registry_snapshot_read !== true) {
      failures.push(
        "registry writer review requires a read adapter with registry_snapshot_read=true",
      );
    }
  }

  const flowId = readFlowId(parsedReadAdapter);
  const operation = readRegistryWriterReviewOperation(parsedReadAdapter);
  if (operation === "blocked" && failures.length === 0) {
    failures.push(
      "registry writer review requires would_create_flow or would_update_flow comparison",
    );
  }

  const validationStatus = failures.length === 0 ? "pass" : "fail";
  const proposedWrite =
    validationStatus === "pass" && operation !== "blocked"
      ? {
          flow_id: flowId,
          sync_mode: "managed" as const,
          registry_target: "task_flow_registry" as const,
          operation,
          expected_current_state:
            operation === "create" ? ("missing" as const) : ("present" as const),
          rollback_path:
            "Do not write the Task Flow registry; discard this review artifact and return to the read adapter artifact.",
        }
      : null;
  const outputDir = ensureInsideWorkspace(
    params.repoRoot,
    params.outputDir ?? "reports/hermes-agent/state",
  );
  await mkdir(outputDir, { recursive: true });
  const review: HermesTaskFlowRegistryWriterReview = {
    schema: "openclaw.hermes.taskflow_registry_writer_review.v1",
    created_at: (params.now ?? new Date()).toISOString(),
    dry_run: true,
    review_only: true,
    source_read_adapter: readAdapterPath,
    flow_id: flowId,
    status: validationStatus === "pass" ? "manual_approval_required" : "blocked",
    requested_action: "review_future_taskflow_registry_write",
    operation: validationStatus === "pass" ? operation : "blocked",
    registry_snapshot_required: true,
    operator_approval_required: true,
    taskflow_registry_write: false,
    sqlite_write: false,
    worker_execution: false,
    model_invoked: false,
    validation_status: validationStatus,
    failures,
    proposed_write: proposedWrite,
    approval_requirements: [
      "read adapter validation_status must be pass",
      "registry_snapshot_read must be true",
      "comparison must be would_create_flow or would_update_flow",
      "operator must approve before any future registry writer exists",
    ],
    blocked_actions: [
      "automatic Task Flow registry write",
      "SQLite registry mutation",
      "worker execution from writer review",
      "model invocation during writer review",
    ],
    next_safe_task:
      validationStatus === "pass"
        ? "Add a final no-op writer apply gate that still keeps Task Flow registry writes disabled."
        : "Fix the read adapter report before any writer review.",
  };
  const filePath = resolve(outputDir, flowId + "-taskflow-registry-writer-review.json");
  await writeFile(filePath, JSON.stringify(review, null, 2) + "\n", "utf8");
  return {
    path: filePath,
    review,
  };
}

