export async function writeHermesTaskFlowRegistryContractCoverageReportArtifact(params: {
  repoRoot: string;
  writerContractFixturePath: string;
  outputDir?: string;
  now?: Date;
}): Promise<HermesTaskFlowRegistryContractCoverageReportArtifact> {
  const writerContractFixturePath = ensureInsideWorkspace(
    params.repoRoot,
    params.writerContractFixturePath,
  );
  const failures: string[] = [];
  let parsedFixture: unknown;

  try {
    parsedFixture = JSON.parse(await readFile(writerContractFixturePath, "utf8"));
  } catch (error) {
    failures.push(
      "writer contract fixture JSON parse failed: " +
        (error instanceof Error ? error.message : String(error)),
    );
  }

  if (parsedFixture !== undefined) {
    failures.push(...validateHermesTaskFlowRegistryWriterContractFixture(parsedFixture));
  }

  const fixtureRecord = isRecord(parsedFixture) ? parsedFixture : null;
  const writerContract =
    fixtureRecord !== null && isRecord(fixtureRecord.writer_contract)
      ? fixtureRecord.writer_contract
      : null;
  const flowId = readFlowId(parsedFixture);
  const operation = readRegistryWriterContractFixtureOperation(parsedFixture);
  const outputDir = ensureInsideWorkspace(
    params.repoRoot,
    params.outputDir ?? "reports/hermes-agent/state",
  );
  await mkdir(outputDir, { recursive: true });

  const requiredFieldChecks = [
    {
      name: "writer_contract.flow_id",
      passed: typeof writerContract?.flow_id === "string" && writerContract.flow_id === flowId,
    },
    { name: "writer_contract.sync_mode", passed: writerContract?.sync_mode === "managed" },
    {
      name: "writer_contract.registry_target",
      passed: writerContract?.registry_target === "task_flow_registry",
    },
    { name: "writer_contract.operation", passed: writerContract?.operation === operation },
    {
      name: "writer_contract.expected_current_state",
      passed:
        operation === "create"
          ? writerContract?.expected_current_state === "missing"
          : operation === "update" && writerContract?.expected_current_state === "present",
    },
    {
      name: "writer_contract.commit_strategy",
      passed: writerContract?.commit_strategy === "disabled",
    },
    {
      name: "writer_contract.taskflow_registry_write",
      passed: writerContract?.taskflow_registry_write === false,
    },
    { name: "writer_contract.sqlite_write", passed: writerContract?.sqlite_write === false },
    {
      name: "writer_contract.rollback_path",
      passed:
        typeof writerContract?.rollback_path === "string" &&
        writerContract.rollback_path.trim() !== "",
    },
  ];
  const safetyFlagChecks = [
    { name: "operator_approved", passed: fixtureRecord?.operator_approved === false },
    { name: "registry_write_allowed", passed: fixtureRecord?.registry_write_allowed === false },
    { name: "taskflow_registry_write", passed: fixtureRecord?.taskflow_registry_write === false },
    { name: "sqlite_write", passed: fixtureRecord?.sqlite_write === false },
    { name: "worker_execution", passed: fixtureRecord?.worker_execution === false },
    { name: "model_invoked", passed: fixtureRecord?.model_invoked === false },
    {
      name: "writer_contract.commit_strategy",
      passed: writerContract?.commit_strategy === "disabled",
    },
    {
      name: "writer_contract.taskflow_registry_write",
      passed: writerContract?.taskflow_registry_write === false,
    },
    { name: "writer_contract.sqlite_write", passed: writerContract?.sqlite_write === false },
  ];
  const validationStatus = failures.length === 0 ? "pass" : "fail";
  const requiredFieldsPassed =
    validationStatus === "pass" && requiredFieldChecks.every((check) => check.passed);
  const safetyFlagsPassed =
    validationStatus === "pass" && safetyFlagChecks.every((check) => check.passed);
  const totalChecks = requiredFieldChecks.length + safetyFlagChecks.length;
  const passedChecks =
    validationStatus === "pass"
      ? [...requiredFieldChecks, ...safetyFlagChecks].filter((check) => check.passed).length
      : 0;
  const coverageRatio = totalChecks === 0 ? 0 : Number((passedChecks / totalChecks).toFixed(4));
  const coveragePass = requiredFieldsPassed && safetyFlagsPassed && coverageRatio === 1;

  const report: HermesTaskFlowRegistryContractCoverageReport = {
    schema: "openclaw.hermes.taskflow_registry_contract_coverage_report.v1",
    created_at: (params.now ?? new Date()).toISOString(),
    dry_run: true,
    read_only: true,
    source_writer_contract_fixture: writerContractFixturePath,
    flow_id: flowId,
    status: coveragePass ? "coverage_pass" : "blocked",
    operation: coveragePass ? operation : "blocked",
    validation_status: validationStatus,
    failures,
    coverage: {
      required_fields_checked: requiredFieldChecks.map((check) => check.name),
      safety_flags_checked: safetyFlagChecks.map((check) => check.name),
      required_fields_passed: requiredFieldsPassed,
      safety_flags_passed: safetyFlagsPassed,
      coverage_ratio: coverageRatio,
    },
    registry_write_allowed: false,
    taskflow_registry_write: false,
    sqlite_write: false,
    worker_execution: false,
    model_invoked: false,
    blocked_actions: [
      "Task Flow registry write",
      "SQLite registry mutation",
      "worker execution from contract coverage report",
      "model invocation during contract coverage report",
      "automatic promotion from coverage report to real writer",
    ],
    rollback_path:
      "Discard this read-only contract coverage report; it did not persist registry, SQLite, worker, or model state.",
    next_safe_task: coveragePass
      ? "Add a read-only promotion preflight report that proves coverage stays green before any real writer exists."
      : "Fix the writer contract fixture before any future promotion preflight report.",
  };
  const filePath = resolve(outputDir, flowId + "-taskflow-registry-contract-coverage-report.json");
  await writeFile(filePath, JSON.stringify(report, null, 2) + "\n", "utf8");
  return {
    path: filePath,
    report,
  };
}

