  const requiredBefore = readStringArray(value.approval_required_before);
  for (const required of [
    "registry_read_adapter",
    "registry_write_adapter",
    "worker_execution",
    "model_invocation",
  ]) {
    if (!requiredBefore.includes(required)) {
      failures.push("approval_required_before must include " + required);
    }
  }
  if (!Array.isArray(value.preview_diff) || value.preview_diff.length === 0) {
    failures.push("preview_diff must include at least one registry operation");
  } else {
    for (const entry of value.preview_diff) {
      if (!isRecord(entry)) {
        failures.push("preview_diff entries must be JSON objects");
        continue;
      }
      expectField(entry, "op", "preview_create_or_update_flow", failures, "preview_diff");
      expectField(entry, "sync_mode", "managed", failures, "preview_diff");
      expectField(entry, "registry_target", "task_flow_registry", failures, "preview_diff");
      if (entry.flow_id !== value.flow_id) {
        failures.push("preview_diff.flow_id must match flow_id");
      }
    }
  }

  return failures;
