function isRegistryWouldWrite(
  value: unknown,
): value is NonNullable<HermesTaskFlowRegistryNoopWriteRecord["would_write"]> {
  return (
    isRecord(value) &&
    typeof value.flow_id === "string" &&
    value.flow_id.trim() !== "" &&
    value.sync_mode === "managed" &&
    value.registry_target === "task_flow_registry"
  );
}

function isRegistryProposedWrite(
  value: unknown,
): value is NonNullable<HermesTaskFlowRegistryWriterReview["proposed_write"]> {
  return (
    isRecord(value) &&
    typeof value.flow_id === "string" &&
    value.flow_id.trim() !== "" &&
    value.sync_mode === "managed" &&
    value.registry_target === "task_flow_registry" &&
    (value.operation === "create" || value.operation === "update") &&
    (value.expected_current_state === "missing" || value.expected_current_state === "present") &&
    typeof value.rollback_path === "string" &&
    value.rollback_path.trim() !== ""
  );
}

